/// Parity (oracle): `ferrolearn_linear::LassoLars::fit` matches sklearn
/// `LassoLars(alpha=1.0)` on diabetes — a sparser knot than alpha=0.1/0.5,
/// admitting only [2, 3, 8]. Mirrors `sklearn/linear_model/_least_angle.py:413+`
/// (`method == "lasso"`). Expected values are the live sklearn 1.5.2 oracle
/// (R-CHAR-3).
#[test]
fn parity_lasso_lars_coef_alpha_1_0() {
    let (x, y) = diabetes();
    let fitted = LassoLars::<f64>::new().with_alpha(1.0).fit(&x, &y).unwrap();
    let coef = fitted.coefficients();

    let ferro_active: Vec<usize> = coef
        .iter()
        .enumerate()
        .filter(|&(_, &c)| c.abs() > 1e-9)
        .map(|(i, _)| i)
        .collect();
    assert_eq!(
        ferro_active,
        SK_LASSO_A10_ACTIVE.to_vec(),
        "active set diverges: ferrolearn {ferro_active:?} vs sklearn {SK_LASSO_A10_ACTIVE:?}"
    );

    for (j, &sk) in SK_LASSO_A10.iter().enumerate() {
        let got = coef[j];
        assert!(
            (got - sk).abs() <= 1e-4,
            "coef[{j}] diverges: ferrolearn {got} vs sklearn {sk}"
        );
    }
    assert!(
        (fitted.intercept() - SK_LASSO_A10_INTERCEPT).abs() <= 1e-4,
        "intercept diverges: ferrolearn {} vs sklearn {SK_LASSO_A10_INTERCEPT}",
        fitted.intercept()
    );
}

/// Control (ISOLATION): `ferrolearn_linear::Lars::fit` (`method="lar"`) matches
/// sklearn `Lars(n_nonzero_coefs=5)` EXACTLY on diabetes, confirming the LARS
/// homotopy machinery (`fn lars_path` with `lasso_modification=false`) is
/// correct. This PASSES -- the divergence above is isolated to the LassoLars
/// lasso-path algorithm, NOT the LARS equiangular machinery. Regression guard.
/// Mirrors `sklearn/linear_model/_least_angle.py` `_lars_path_solver`
/// (`method == "lar"`).
#[test]
fn control_lars_coef_matches_sklearn() {
    let (x, y) = diabetes();
    let fitted = Lars::<f64>::new()
        .with_n_nonzero_coefs(5)
        .fit(&x, &y)
        .unwrap();
    let coef = fitted.coefficients();
    for (j, &sk) in SK_LARS_5.iter().enumerate() {
        let got = coef[j];
        assert!(
            (got - sk).abs() <= 1e-6,
            "Lars coef[{j}] regressed: ferrolearn {got} vs sklearn {sk}"
        );
    }
    assert!(
        (fitted.intercept() - SK_LARS_5_INTERCEPT).abs() <= 1e-6,
        "Lars intercept regressed: ferrolearn {} vs sklearn {SK_LARS_5_INTERCEPT}",
        fitted.intercept()
    );
}
